// Эта инструкция обязательно должна быть первой, т.к. этот код компилируется в бинарный,// и загрузчик передает управление по адресу первой инструкции бинарного образа ядра ОС.__asm("jmp kmain");#define VIDEO_BUF_PTR (0xb8000)///#define CURSOR_PORT (0x3D4)#define VIDEO_WIDTH (80) // Ширина текстового экрана#define IDT_TYPE_INTR (0x0E)#define IDT_TYPE_TRAP (0x0F)// Селектор секции кода, установленный загрузчиком ОС#define GDT_CS (0x8)#define PIC1_PORT (0x20)#define LSHIFT 42#define RSHIFT 0x36int zaglav = 0;int color;int pos = 0;int num_str = 0;void backspace();void out_str(const char* ptr);void vyvod_symv(int scan_code);void cursor_moveto(unsigned int strnum, unsigned int pos);void enter();void probel();int pow(int osnovanie, unsigned int exp);int perevod_10_SS(char *chislo, int ishod_SS, int dlina_chisla);void perevod_itog_SS(int num_in10SS, int todo_SS);void posixtime(char* commands, int index);void time(int ishod_seconds, int ishod_minutes, int ishod_hours, int days, int start);void prokrutka(void);char klavisha[56] = {0};int pow(int osnovanie, int step){  int result = 1;  for(; step > 0; step--)     result *= osnovanie;  return result;}void fill_table() // Заполняет таблицу при запуске ядра{        klavisha[2]='1';	klavisha[3]='2';	klavisha[4]='3';	klavisha[5]='4';	klavisha[6]='5';	klavisha[7]='6';	klavisha[8]='7';	klavisha[9]='8';	klavisha[10]='9';	klavisha[11]='0';	klavisha[12]='-';	klavisha[13]='=';	klavisha[14]='0';	klavisha[15]='\t';	klavisha[16]='q';	klavisha[17]='w';	klavisha[18]='e';	klavisha[19]='r';	klavisha[20]='t';	klavisha[21]='y';	klavisha[22]='u';	klavisha[23]='i';	klavisha[24]='o';	klavisha[25]='p';	klavisha[26]='[';	klavisha[27]=']';	klavisha[28]='\n';	klavisha[29]='0';	klavisha[30]='a';	klavisha[31]='s';	klavisha[32]='d';	klavisha[33]='f';	klavisha[34]='g';	klavisha[35]='h';	klavisha[36]='j';	klavisha[37]='k';	klavisha[38]='l';	klavisha[39]=';';	klavisha[40]='\'';	klavisha[41]='`';	klavisha[42]='0';	klavisha[44]='z';	klavisha[45]='x';	klavisha[46]='c';	klavisha[47]='v';	klavisha[48]='b';	klavisha[49]='n';	klavisha[50]='m';	klavisha[51]=',';	klavisha[52]='.';	klavisha[53]='/';	klavisha[55]=' ';}void vyvod_symv(int scan_code){    if (pos==40)        return;          unsigned char* video_buf = (unsigned char*) VIDEO_BUF_PTR + 2 * pos + 80 * 2 * num_str;    if(!zaglav)      video_buf[0] = klavisha[scan_code];    else    {      if (klavisha[scan_code] == '8')        video_buf[0] = '*';      else if (klavisha[scan_code] == '=')        video_buf[0] = '+';      else        video_buf[0] = klavisha[scan_code] - 32;    }    video_buf[1] = color;    video_buf[2] = '\0';    video_buf[3] = color;    pos++;    cursor_moveto(num_str, pos);}void on_key(int scan_code){  if (scan_code == LSHIFT)    zaglav = 1;  else if (scan_code == RSHIFT)    zaglav = 0;  else if (scan_code == 57) probel();  else if (scan_code == 28) enter();  else if (scan_code == 14) backspace();  else vyvod_symv(scan_code);}// Структура описывает данные об обработчике прерыванияstruct idt_entry{    unsigned short base_lo; // Младшие биты адреса обработчика    unsigned short segm_sel; // Селектор сегмента кода    unsigned char always0; // Этот байт всегда 0    unsigned char flags; // Флаги тип. Флаги: P, DPL, Типы - это константы - IDT_TYPE...    unsigned short base_hi; // Старшие биты адреса обработчика} __attribute__((packed)); // Выравнивание запрещено// Структура, адрес которой передается как аргумент команды lidtstruct idt_ptr{    unsigned short limit;    unsigned int base;} __attribute__((packed)); // Выравнивание запрещеноstruct idt_entry g_idt[256]; // Реальная таблица IDTstruct idt_ptr g_idtp; // Описатель таблицы для команды lidt// Пустой обработчик прерываний. Другие обработчики могут быть реализованы по этому шаблонуvoid default_intr_handler(){    asm("pusha");    // ... (реализация обработки)    asm("popa; leave; iret");}typedef void (*intr_handler)();void intr_reg_handler(int num, unsigned short segm_sel, unsigned short flags, intr_handler hndlr){    unsigned int hndlr_addr = (unsigned int) hndlr;    g_idt[num].base_lo = (unsigned short) (hndlr_addr & 0xFFFF);    g_idt[num].segm_sel = segm_sel;    g_idt[num].always0 = 0;    g_idt[num].flags = flags;    g_idt[num].base_hi = (unsigned short) (hndlr_addr >> 16);}static inline unsigned char inb (unsigned short port) // Чтение из порта{  unsigned char data;  asm volatile ("inb %w1, %b0" : "=a" (data) : "Nd" (port));  return data;}static inline void outb (unsigned short port, unsigned char data) // Запись{  asm volatile ("outb %b0, %w1" : : "a" (data), "Nd" (port));}// Функция инициализации системы прерываний: заполнение массива с адресами обработчиковvoid intr_init() //методичка{  int idt_count = sizeof(g_idt) / sizeof(g_idt[0]);  for(int i = 0; i < idt_count; i++)      intr_reg_handler(i, GDT_CS, 0x80 | IDT_TYPE_INTR, default_intr_handler); // segm_sel=0x8, P=1, DPL=0, Type=Intr (необходимые обработчики могут быть зарегистрированы)}void intr_start() //методичка{    int idt_count = sizeof(g_idt) / sizeof(g_idt[0]);    g_idtp.base = (unsigned int) (&g_idt[0]);    g_idtp.limit = (sizeof (struct idt_entry) * idt_count) - 1;    asm("lidt %0" : : "m" (g_idtp) );}void intr_enable() //методичка{    asm("sti");}void keyb_process_keys() //методичка{    // Проверка что буфер PS/2 клавиатуры не пуст (младший бит присутствует)    if (inb(0x64) & 0x01)     {        unsigned char scan_code;        unsigned char state;        scan_code = inb(0x60); // Считывание символа с PS/2 клавиатуры        if (scan_code < 128) // Скан-коды выше 128 - это отпускание клавиши            on_key(scan_code);    }}void keyb_handler() //методичка{    asm("pusha");    // Обработка поступивших данных    keyb_process_keys();    // Отправка контроллеру 8259 нотификации о том, что прерывание обработано        outb(PIC1_PORT, 0x20);     asm("popa; leave; iret");}void keyb_init() //методичка{    // Регистрация обработчика прерывания    intr_reg_handler(0x09, GDT_CS, 0x80 | IDT_TYPE_INTR, keyb_handler);     // segm_sel=0x8, P=1, DPL=0, Type=Intr    // Разрешение только прерываний клавиатуры от контроллера 8259    outb(PIC1_PORT + 1, 0xFF ^ 0x02); // 0xFF - все прерывания, 0x02 -бит IRQ1 (клавиатура).      // Разрешены будут только прерывания, чьи биты установлены в 0}// Функция переводит курсор на строку strnum (0 – самая верхняя) в позицию//pos на этой строке (0 – самое левое положение).void cursor_moveto(unsigned int strnum, unsigned int pos) //методичка{  unsigned short new_pos = (strnum * VIDEO_WIDTH) + pos;  outb(CURSOR_PORT, 0x0F);  outb(CURSOR_PORT + 1, (unsigned char)(new_pos & 0xFF));  outb(CURSOR_PORT, 0x0E);  outb(CURSOR_PORT + 1, (unsigned char)( (new_pos >> 8) & 0xFF));}void clear() {	unsigned char* video_buf = (unsigned char*) VIDEO_BUF_PTR; //самое начало		for (int i = 0; i < 80*25*2; i += 2) //ширина*высота (ячейка и цвет)	{	  video_buf[i] = '\0';	  video_buf[i + 1] = color;	}	pos = 0;	num_str = 0;	cursor_moveto(0, 0);}void shutdown(){      asm("outw %w0, %w1" : : "a" (0x2000), "Nd" (0x604)); //запись последовательности байтов в порты ввода-вывода}void info(){   out_str("Valentina Yasybash, group 4831001/10001, gcc AT&T.");   if (color == 0x0f)          out_str("Selected color: white.");    else if (color == 0x08)          out_str("Selected color: gray.");                       else if (color == 0x02)          out_str("Selected color: green.");              else if (color == 0x04)          out_str("Selected color: red.");                      else if (color == 0x0E)          out_str("Selected color: yellow.");              else if (color == 0x09)          out_str("Selected color: blue.");}void nsconv(char* commands, int index){  int ishod_SS = 0;  int todo_SS = 0;  char chislo[40] = {0};   int kol = 0;  int num_in10SS = 0;   index+=2;  int i=0;  for (; commands[index]!=' '; index++, i++) //Находим первое число и записываем в виде строки  {    chislo[i] = commands[index];   }  int dlina_chisla=i;  index++;    for (; commands[index]!=' '; index++) //Находим второе число и записываем в виде числа  {    ishod_SS *= 10;    ishod_SS += commands[index] - '0';  }  index++;    for (; commands[index]!='\0'; index++) //Находим третье число и записываем в виде числа  {    todo_SS *= 10;    todo_SS += commands[index] - '0';  }    num_in10SS = perevod_10_SS(chislo, ishod_SS, dlina_chisla);    perevod_itog_SS(num_in10SS, todo_SS);}      int check_overflow(int num_in10SS, int itog) //{  if (num_in10SS > 0)    if (itog > (2147483647 - num_in10SS)) return 0; //макс инт  else     if (itog < (-2147483648 - num_in10SS)) return 0; //мин  return 1;}int perevod_10_SS(char* chislo, int ishod_SS, int dlina_chisla){   int itog = 0;   int num_in10SS;      for (int i = 0, len = dlina_chisla; i < len; i++, dlina_chisla--)   {      if (chislo[i] >='0' && chislo[i] <= '9') //если символ цифра      {        int num = chislo[i] - '0';        if (num < ishod_SS)         {          num_in10SS = num * pow(ishod_SS, dlina_chisla - 1); //перевод в 10СС          if (!check_overflow(num_in10SS, itog))          {            out_str("error: int overflow");            return -1;          }        itog += num_in10SS;         }        else        {           char oshibka[18] = "invalid symbol: ?";  //?           oshibka[16] = chislo[i];           out_str(oshibka);           return -1;         }      }      else     {        int num = chislo[i] - 'a' + 10;      if (num < ishod_SS)       {        num_in10SS = num * pow(ishod_SS, dlina_chisla - 1);        if (!check_overflow(num_in10SS, itog))          {            out_str("error: int overflow");            return -1;          }        itog += num_in10SS;              }      else       {        char oshibka[18] = "invalid symbol: ?";        oshibka[16] = chislo[i];        out_str(oshibka);        return -1;       }    }  } return itog;}void perevod_itog_SS(int num_in10SS, int todo_SS){  char otvet[80] = {0};  char otv_naoborot[80] = {0};  int i = 0;  for (; num_in10SS!=0; i++, num_in10SS /= todo_SS)  {    if ((num_in10SS % todo_SS) < 10)      otv_naoborot[i] = '0' + (num_in10SS % todo_SS);    else       otv_naoborot[i] = 'a' + ((num_in10SS % todo_SS) - 10);  }    i--;    for (int j = 0; i != -1; j++, i--)    otvet[j]=otv_naoborot[i];  out_str(otvet);}void backspace(){    if (pos == -1)      return;    unsigned char* video_buf = (unsigned char*) VIDEO_BUF_PTR + 2*pos + 80*2*num_str - 2;    video_buf[0] = '\0';    if (pos != 0)        pos--;    cursor_moveto(num_str, pos);}void szconv(char* commands, int l){  char bytes1[3] = {0};  char bytes2[3] = {0};  unsigned long chislo = 0;  char otvet[40]={0};  l += 2;  int prom = l;  for (int u = 0; commands[l]!=' '; u++, l++) //Находим первое число и записываем в виде числа  {    char simv = commands[l];    if (simv>'9' || simv<'0')    {      char oshibka[]="error: invalid size - ?";      oshibka[22] = simv;      out_str(oshibka);      return;    }    otvet[u]=simv;    chislo *= 10;    chislo += simv - '0';  }    if (l - prom - 1 > 10) //len>10  {    out_str("error: int overflow");    return;  }    l++;  for (int i = 0; commands[l]!=' '; i++, l++) //Находим второй аргумент и записываем в виде строки    bytes1[i] = commands[l];    l++;  for (int i = 0; commands[l]!='\0'; i++, l++) //Находим третий аргумент и записываем в виде строки    bytes2[i] = commands[l];    unsigned long itog = chislo;  char index1;  char index2;  char mass[6]="bkmgt";  for (int i=0; mass[i]!='\0'; i++)  {    if (mass[i] == bytes1[0])      index1 = i;    if (mass[i] == bytes2[0])      index2 = i;  }  char razn = index2 - index1;  if (razn == 0)    out_str(otvet);      else if (razn > 0)  {    if (razn ==  4)    {      out_str("0 tb");      return;    }    unsigned long mnozh = pow(1024, razn); // надо делить    unsigned long drobn = itog % mnozh;     itog  /= mnozh; //целая часть    drobn = (drobn * 100) / mnozh; //находим дробную часть    int i = 0;    for (; i < 40; i++)      otvet[i]=0;    i = 0;    do {          otvet[i] = itog % 10 + '0'; //перевод в число          itog /= 10;          i++;    } while (itog != 0);    char itog_otvet[40] = {0};    i--;    int k = 0;    for (; i >= 0; i--, k++) //запись наоборот        itog_otvet[k] = otvet[i];    itog_otvet[k] = '.'; //оформляем    itog_otvet[k + 1] = drobn / 10 + '0';    itog_otvet[k + 2] = drobn % 10 + '0';    itog_otvet[k + 3] = ' ';    itog_otvet[k + 4] = bytes2[0];    itog_otvet[k + 5] = bytes2[1];    out_str(itog_otvet);  }  else   {    if (razn ==  -4)    {      out_str("error: int overflow");      return;    }    razn *= - 1;    while(razn != 0)    {      if (itog > 2147483647)      {        out_str("error: int overflow");        return;      }      razn--;      itog *= 1024;    }        if (itog > 2147483647)    {      out_str("error: int overflow");      return;    }    int i = 0;    for (; i < 40; i++)      otvet[i]=0;    i = 0;    do {          otvet[i] = itog % 10 + '0'; //перевод в число          itog /= 10;          i++;    } while (itog != 0);    char itog_otvet[40] = {0};    i--;    int k = 0;    for (; i >= 0; i--, k++) //запись наоборот        itog_otvet[k] = otvet[i];    itog_otvet[k] = ' ';    itog_otvet[k + 1] = bytes2[0];    itog_otvet[k + 2] = bytes2[1];        out_str(itog_otvet);  }}int proverka_na_visokos(int kol_years){    return ((kol_years % 400 == 0) || ((kol_years % 4 == 0) && (kol_years % 100 != 0)));}void posixtime(char* commands, int index){    unsigned long input_seconds = 0;    index+=2;    for (int i = 0; commands[index] != '\0'; i++, index++) //перевод в число    {        input_seconds += commands[index] - '0';        if (commands[index + 1] != '\0')          input_seconds *= 10;    }    int ishod_seconds = input_seconds % 60; //перевод в целое число секунд    int ishod_minutes = (input_seconds / 60) % 60;    int ishod_hours = (input_seconds / 3600) % 24;    int days = input_seconds / 86400; // Перевод секунд в дни    return time(ishod_seconds, ishod_minutes, ishod_hours, days, 1970);}int del_stroki(char* chislo, char c, int del){    int chast = 0, ostat = 0;    for (int i = 0; chislo[i] != '\0'; i++)    {        ostat += (chislo[i] - '0');        int celoe = ostat /del;        chast += celoe;        ostat -= celoe * del;        ostat *= 10;        chast *= 10;    }    if (c == '/')        return chast / 10;    else if (c == '%')        return ostat / 10;    return -1;}void wintime(char* commands, int index){    char input_seconds[22] = {0};    index += 2;    int i = 0;    for (; commands[index] != '\0' && i < 20; i++, index++)        input_seconds[i] = commands[index];    if (i>=7)      for (int l=i-1; l>=i-7; l--) //100 наносекунд это 10^-7 секунд => отбрасываем 7 последних цифр (не влияют на точность)        input_seconds[l]='\0';    else     {      out_str("01.01.1601 00:00:00");      return;    }    int ishod_seconds = del_stroki(input_seconds, '%', 60);    int ishod_minutes = del_stroki(input_seconds, '/', 60) % 60;    int ishod_hours = del_stroki(input_seconds, '/', 3600) % 24;    int days = del_stroki(input_seconds, '/', 86400);  // Перевод секунд в дни    return time(ishod_seconds, ishod_minutes, ishod_hours, days, 1601);}void time(int ishod_seconds, int ishod_minutes, int ishod_hours, int days, int start){    char itog_otvet[20] = "DD.MM.YYYY hh:mm:ss";    itog_otvet[11] = ishod_hours / 10 + '0';    itog_otvet[12] = ishod_hours % 10 + '0';    itog_otvet[14] = ishod_minutes / 10 + '0';    itog_otvet[15] = ishod_minutes % 10 + '0';    itog_otvet[17] = ishod_seconds / 10 + '0';    itog_otvet[18] = ishod_seconds % 10 + '0';        int kol_years;    for (kol_years = start; days >= 365; kol_years++) // Определение года с учётом високосности    {        if (!proverka_na_visokos(kol_years)) // Не високосный год            days -= 365;        else  // Високосный год        {            if (days >= 366)                days -= 366;            else                break;        }    }    // Теперь в days - остаток дней    int kol_months;    int dop = (proverka_na_visokos(kol_years)) ? 1 : 0;  // Учёт 29-го февраля    itog_otvet[6] = kol_years / 1000 + '0';    itog_otvet[7] = (kol_years % 1000) / 100 + '0';    itog_otvet[8] = (kol_years % 100) / 10 + '0';    itog_otvet[9] = kol_years % 10 + '0';        if (days >= 31)  // Как минимум, февраль    {        if (days >= 59 + dop)  // Как минимум, март        {            if (days >= 89 + dop) // Как минимум, апрель            {                if (days >= 120 + dop) // Как минимум, май                {                    if (days >= 150 + dop) // Как минимум, июнь                    {                        if (days >= 181 + dop)  // Как минимум, июль                        {                            if (days >= 211 + dop)  // Как минимум, август                            {                                if (days >= 242 + dop) // Как минимум, сентябрь                                {                                    if (days >= 273 + dop) // Как минимум, октябрь                                    {                                        if (days >= 304 + dop) // Как минимум, ноябрь                                        {                                            if (days >= 334 + dop) // Точно декабрь                                            {                                                kol_months = 12;                                                days -= 334 + dop;                                            }                                            else // Точно ноябрь                                            {                                                kol_months = 11;                                                days -= 304 + dop;                                            }                                        }                                        else  // Точно октябрь                                        {                                            kol_months = 10;                                            days -= 273 + dop;                                        }                                    }                                    else // Точно сентябрь                                    {                                        kol_months = 9;                                        days -= 242 + dop;                                    }                                }                                else // Точно август                                {                                    kol_months = 8;                                    days -= 211 + dop;                                }                            }                            else  // Точно июль                            {                                kol_months = 7;                                days -= 181 + dop;                            }                        }                        else // Точно июнь                        {                            kol_months = 6;                            days -= 150 + dop;                        }                    }                    else // Точно май                    {                        kol_months = 5;                        days -= 120 + dop;                    }                }                else // Точно апрель                {                    kol_months = 4;                    days -= 89 + dop;                }            }            else // Точно март            {                kol_months = 3;                days -= 59 + dop;            }        }        else // Точно ферваль        {            kol_months = 2;            days -= 31;        }    }    else // Точно январь        kol_months = 1;         itog_otvet[3] = kol_months / 10 + '0'; //Записываем месяц    itog_otvet[4] = kol_months % 10 + '0';    int itog_days = 1 + days;    itog_otvet[0] = itog_days / 10 + '0'; //Записываем дни    itog_otvet[1] = itog_days % 10 + '0';    out_str(itog_otvet);}void enter(){    unsigned char* video_buf = (unsigned char*) VIDEO_BUF_PTR + 80 * 2 * num_str;    char commands[80] = {0};    int k = 0;    num_str++;    int j = 0;    while (k < 80 * 2 - 2) //Аргументы командной строки    {        commands[j++] = video_buf[k];        k+=2;    }        pos = 0;    int i = 0;        for (; commands[i]!='i' && commands[i]!='c' && commands[i]!='s' && commands[i]!='n' && commands[i]!='p' && commands[i]!='w' && i<81; i++); //ищем какую-нибудь команду            if (commands[i-1]=='\0' && commands[i]=='s')      {        int dop = i;        if (commands[++i]=='z' && commands[++i]=='c' && commands[++i]=='o' && commands[++i]=='n' && commands[++i]=='v')          szconv(commands, i);                  if (commands[++dop]=='h' && commands[++dop]=='u' && commands[++dop]=='t' && commands[++dop]=='d' && commands[++dop]=='o' && commands[++dop]=='w' && commands[++dop]=='n' && commands[++dop]=='\0')          shutdown();      }      else if (commands[i-1]=='\0' && commands[i]=='i' && commands[++i]=='n' && commands[++i]=='f' && commands[++i]=='o' && commands[++i]=='\0')        info();      else if (commands[i-1]=='\0' && commands[i]=='c' && commands[++i]=='l' && commands[++i]=='e' && commands[++i]=='a' && commands[++i]=='r' && commands[++i]=='\0')        clear();      else if (commands[i-1]=='\0' && commands[i]=='n' && commands[++i]=='s' && commands[++i]=='c' && commands[++i]=='o' && commands[++i]=='n' && commands[++i]=='v')         nsconv(commands, i);      else if (commands[i-1]=='\0' && commands[i]=='p' && commands[++i]=='o' && commands[++i]=='s' && commands[++i]=='i' && commands[++i]=='x' && commands[++i]=='t' && commands[++i]=='i' && commands[++i]=='m' && commands[++i]=='e')         posixtime(commands, i);      else if (commands[i-1]=='\0' && commands[i]=='w' && commands[++i]=='i' && commands[++i]=='n' && commands[++i]=='t' && commands[++i]=='i' && commands[++i]=='m' && commands[++i]=='e')         wintime(commands, i);       else         out_str("Error: command not recognized");                if(num_str>24)          prokrutka();}void probel(){    if (pos == 40)        return;    unsigned char* video_buf = (unsigned char*) VIDEO_BUF_PTR + 2 * pos + 80 * 2 * num_str; //получаем указатель на первое свободное место для нового символа в буфере видеоадаптера    video_buf[0] = ' ';    video_buf[1] = color;    video_buf[2] = '\0'; //очищаем место для следующего символа (на всякий случай)    video_buf[3] = color;    pos++;    cursor_moveto(num_str, pos);}void out_str(const char* ptr) //методичка{    if (num_str > 24)        prokrutka();    unsigned char* video_buf = (unsigned char*) VIDEO_BUF_PTR + 80 * 2 * num_str;    while (*ptr)    {		video_buf[0] = (unsigned char)*ptr; // Символ (код)		video_buf[1] = color; // Цвет символа и фона		video_buf += 2;		ptr++;    }    num_str++;    pos = 0;    if (num_str > 24)      prokrutka();    cursor_moveto(num_str, 0);}void prokrutka(){    unsigned char* video_buf = (unsigned char*) VIDEO_BUF_PTR;    int i = 0;    for (; i < 25 * 80; i++)    {        video_buf[0]=video_buf[80*2];        video_buf[1] = color;        video_buf +=2;    }    for (i = 0; i < 80; i++)    {        video_buf[0] = 0;        video_buf[1] = color;        video_buf +=2;    }    pos = 0;    num_str = 24;    cursor_moveto(24, 0);}extern "C" int kmain(){    const char* hello = "Welcome to HelloWorldOS (gcc edition)!";    color = *((int*)0x467); //установка цвета    clear();    num_str = 0;    out_str(hello);    fill_table();    intr_init(); //инициализация прерываний    intr_start(); //Регистрация таблицы дескрипторов прерываний    keyb_init(); //регистрирует обработчик прерывания клавиатуры и разрешает контроллеру прерываний его вызывать в случае нажатия пользователем клавиши клавиатуры    intr_enable(); //Включение прерываний		    // Бесконечный цикл    while (1)    {      asm("hlt");    }    return 0;}